import React, { useMemo, useState, useCallback } from 'react';
import { useQuery } from '@tanstack/react-query';
import { FixedSizeList as List } from 'react-window';
import AddPurchase from './AddPurchase.js';
import InstOut from './InstOut.js';
import VendPurc from './VendPurc.js';
import './PurchaseFunc.css';

const PurchaseFunc = ({ apiBaseUrl }) => {
  const [editingPurchase, setEditingPurchase] = useState(null);
  const [selectedOutflowRow, setSelectedOutflowRow] = useState(null);
  const [showAddInstOutflowForm, setShowAddInstOutflowForm] = useState(false);
  const [showVendPurc, setShowVendPurc] = useState(false);
  const [globalFilter, setGlobalFilter] = useState('');

  // Fetching data using React Query
  const { data: purchases, isLoading, isError, refetch } = useQuery(['purchases'], () =>
    fetch(`${apiBaseUrl}/PurchasesAPI`).then((res) => res.json())
  );

  const { data: locations } = useQuery(['locations'], () =>
    fetch(`${apiBaseUrl}/LocationsAPI`).then((res) => res.json())
  );

  const { data: materials } = useQuery(['materials'], () =>
    fetch(`${apiBaseUrl}/materiallist`).then((res) => res.json())
  );

  const { data: vendors } = useQuery(['vendors'], () =>
    fetch(`${apiBaseUrl}/vendors`).then((res) => res.json())
  );

  // Filtering data
  const filteredData = useMemo(() => {
    if (!purchases || !locations || !vendors || !materials) return [];
    return purchases.filter((purchase) => {
      const location = locations.find((loc) => loc.id === purchase.location);
      const vendor = vendors.find((v) => v.vendorid === purchase.vendor);
      const material = materials.find((m) => m.matid === purchase.materialid);

      const purchaseString = [
        purchase.id,
        location?.locationname,
        vendor?.name,
        material?.name,
        purchase.quantity,
      ]
        .join(' ')
        .toLowerCase();

      return purchaseString.includes(globalFilter.toLowerCase());
    });
  }, [purchases, locations, vendors, materials, globalFilter]);

  // Add purchase
  const handleAdd = useCallback(async (newPurchase) => {
    try {
      await fetch(`${apiBaseUrl}/PurchasesAPI`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newPurchase),
      });
      refetch();
    } catch (error) {
      console.error('Error adding purchase:', error.message);
    }
  }, [apiBaseUrl, refetch]);

  // Row component for virtualization
  const Row = ({ index, style }) => {
    const purchase = filteredData[index];
    return (
      <div style={style} className="purchase-row">
        <p><strong>{purchase.name}</strong></p>
        <p>Location: {locations.find((loc) => loc.id === purchase.location)?.locationname || 'N/A'}</p>
        <p>Vendor: {vendors.find((v) => v.vendorid === purchase.vendor)?.name || 'N/A'}</p>
        <p>Quantity: {purchase.quantity}</p>
      </div>
    );
  };

  if (isLoading) return <p>Loading purchases...</p>;
  if (isError) return <p>Error fetching purchases!</p>;

  return (
    <div className="container">
      <h2>Purchases</h2>
      <AddPurchase handleAdd={handleAdd} locations={locations} vendors={vendors} materials={materials} />
      <input
        value={globalFilter}
        onChange={(e) => setGlobalFilter(e.target.value)}
        placeholder="Search purchases"
        className="search-input"
      />
      <div className="list-container">
        <List
          height={400} // Container height
          itemCount={filteredData.length} // Number of items
          itemSize={50} // Height of each row
          width="100%" // Full width
        >
          {Row}
        </List>
      </div>
      {showAddInstOutflowForm && selectedOutflowRow && (
        <div className="overlay">
          <div className="popup">
            <span className="close-popup" onClick={() => setShowAddInstOutflowForm(false)}>
              &times;
            </span>
            <InstOut
              locations={locations}
              materials={materials}
              purchases={purchases}
              selectedRow={selectedOutflowRow}
              apiBaseUrl={apiBaseUrl}
            />
          </div>
        </div>
      )}
      {showVendPurc && (
        <div className="overlay">
          <div className="popup">
            <span className="close-popup" onClick={() => setShowVendPurc(false)}>
              &times;
            </span>
            <VendPurc purchases={purchases} vendors={vendors} materials={materials} />
          </div>
        </div>
      )}
    </div>
  );
};

export default PurchaseFunc;
